import { createClient } from '@supabase/supabase-js';

// Cấu hình cứng (Hardcoded) cho môi trường Dev
const supabaseUrl = 'https://jcwwdygmtzaausggxxkk.supabase.co';
const supabaseAnonKey = 'sb_publishable_0VNJv-vgufr0Vlh0Bc_bGg_0VDoEphS';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import React, { useState, useMemo, useEffect } from 'react';
import { Lead, Sale, AppView, Customer, CustomerData, StatusConfig, Note } from './types';
import { supabase } from './lib/supabaseClient';
import LeadDetailModal from './components/LeadDetailModal';
import AddLeadModal from './components/AddLeadModal';
import KanbanBoard from './components/KanbanBoard';
import CalendarView from './components/CalendarView';
import Sidebar from './components/Sidebar';
import MainHeader from './components/MainHeader';
import CustomerList from './components/CustomerList';
import CustomerDetailView from './components/CustomerDetailView';
import StatusManagementModal from './components/StatusManagementModal';
import CskhView from './components/CskhView';
import CustomerFormModal from './components/CustomerFormModal';

// --- Helper to map DB snake_case to Frontend types ---
const mapDbLeadToAppLead = (dbLead: any): Lead => ({
    id: dbLead.id,
    name: dbLead.customers?.name || 'Unknown',
    phone: dbLead.phone,
    source: dbLead.source,
    assignedTo: dbLead.assigned_to,
    status: dbLead.status,
    notes: (dbLead.notes || []).map((n: any) => ({
        id: n.id,
        content: n.content,
        createdAt: n.created_at,
        createdBy: n.created_by
    })).sort((a: Note, b: Note) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()),
    createdAt: dbLead.created_at,
    updatedAt: dbLead.updated_at,
    appointmentDate: dbLead.appointment_date,
    projectedAppointmentDate: dbLead.projected_appointment_date,
    service: dbLead.service,
    description: dbLead.description,
    priority: dbLead.priority,
    potentialRevenue: dbLead.potential_revenue,
    cskhStatus: dbLead.cskh_status,
});

const mapDbCustomerToAppCustomerData = (dbCust: any): CustomerData => ({
    name: dbCust.name,
    phone: dbCust.phone,
    email: dbCust.email,
    address: dbCust.address,
    location: dbCust.location,
    generalNotes: dbCust.general_notes,
    tags: dbCust.tags || [],
    taxCode: dbCust.tax_code,
    businessIndustry: dbCust.business_industry,
    customerGroup: dbCust.customer_group,
    website: dbCust.website,
    relationshipStatus: dbCust.relationship_status,
    source: dbCust.source, // Assuming source can be on customer too or derived
    creator: dbCust.creator,
    profileCreatedAt: dbCust.created_at,
    profileCompleteness: dbCust.profile_completeness,
});


function App() {
  // --- STATE ---
  const [leads, setLeads] = useState<Lead[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [statuses, setStatuses] = useState<StatusConfig[]>([]);
  const [cskhStatuses, setCskhStatuses] = useState<StatusConfig[]>([]);
  const [customersData, setCustomersData] = useState<Record<string, CustomerData>>({});

  const [isLoading, setIsLoading] = useState(true);
  const [activeView, setActiveView] = useState<AppView>('customers');
  const [customerViewMode, setCustomerViewMode] = useState<'list' | 'detail'>('list');

  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isStatusModalOpen, setIsStatusModalOpen] = useState(false);
  const [isCskhStatusModalOpen, setIsCskhStatusModalOpen] = useState(false);
  const [newLeadStatus, setNewLeadStatus] = useState<string>('new');
  const [sourceFilter, setSourceFilter] = useState<string>('all');
  const [saleFilter, setSaleFilter] = useState<string>('all');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [currentUser, setCurrentUser] = useState<Sale['id']>('sale1');

  // Customer Form Modal
  const [isCustomerModalOpen, setIsCustomerModalOpen] = useState(false);
  const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null);

  // --- FETCH DATA ---
  const fetchData = async () => {
    setIsLoading(true);
    try {
        // 1. Fetch Sales
        const { data: salesData } = await supabase.from('sales').select('*');
        if (salesData) setSales(salesData);

        // 2. Fetch Statuses
        const { data: statusData } = await supabase.from('status_configs').select('*').order('id'); // You might want a better order field
        if (statusData) {
            const mappedStatuses = statusData.map(s => ({
                id: s.id,
                name: s.name,
                color: { bg: s.bg_color, text: s.text_color, border: s.border_color },
                sla_days: s.sla_days
            }));
            setStatuses(mappedStatuses.filter(s => statusData.find(raw => raw.id === s.id)?.type === 'sales'));
            setCskhStatuses(mappedStatuses.filter(s => statusData.find(raw => raw.id === s.id)?.type === 'cskh'));
        }

        // 3. Fetch Customers
        const { data: custData } = await supabase.from('customers').select('*');
        if (custData) {
            const custMap: Record<string, CustomerData> = {};
            custData.forEach(c => {
                custMap[c.phone] = mapDbCustomerToAppCustomerData(c);
            });
            setCustomersData(custMap);
        }

        // 4. Fetch Leads (with Notes and Customer Name)
        const { data: leadsData, error } = await supabase
            .from('leads')
            .select(`
                *,
                customers (name),
                notes (*)
            `)
            .order('updated_at', { ascending: false });

        if (error) console.error("Error fetching leads:", error);

        if (leadsData) {
            const mappedLeads = leadsData.map(mapDbLeadToAppLead);
            setLeads(mappedLeads);
        }

    } catch (error) {
        console.error("Error loading data:", error);
    } finally {
        setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);


  // --- COMPUTED VALUES ---
  const uniqueSources = useMemo(() => {
    const sources = new Set(leads.map(lead => lead.source));
    return ['all', ...Array.from(sources)];
  }, [leads]);

  const sortedLeads = useMemo(() => {
    const filteredBySource = sourceFilter === 'all'
      ? leads
      : leads.filter(lead => lead.source === sourceFilter);

    const filteredBySale = saleFilter === 'all'
        ? filteredBySource
        : saleFilter === 'unassigned'
            ? filteredBySource.filter(lead => lead.assignedTo === null)
            : filteredBySource.filter(lead => lead.assignedTo === saleFilter);

    return [...filteredBySale].sort((a, b) => new Date(a.updatedAt).getTime() - new Date(b.updatedAt).getTime());
  }, [leads, sourceFilter, saleFilter]);

  const customers = useMemo(() => {
    const customerMap = new Map<string, { name: string; leads: Lead[], phone: string }>();

    leads.forEach(lead => {
        if (!lead.phone) return;
        if (!customerMap.has(lead.phone)) {
            customerMap.set(lead.phone, { name: lead.name, leads: [], phone: lead.phone });
        }
        const customerData = customerMap.get(lead.phone)!;
        customerData.leads.push(lead);
        // Prioritize name from customer record if available, else lead
        if (customersData[lead.phone]?.name) {
             customerData.name = customersData[lead.phone].name!;
        } else if (lead.name.length > customerData.name.length) {
          customerData.name = lead.name;
        }
    });

    // Add customers from customersData who might not have any leads
    Object.entries(customersData).forEach(([phone, data]) => {
        if (!customerMap.has(phone)) {
            customerMap.set(phone, { name: data.name || phone, phone, leads: [] });
        }
    });

    const allCustomers: Customer[] = Array.from(customerMap.values()).map((data) => {
        const persistentData = customersData[data.phone] || { generalNotes: '', tags: [] } as CustomerData;
        // Fix: Spread persistentData FIRST so explicit values can override nulls/undefineds
        return {
            ...persistentData,
            phone: data.phone,
            name: persistentData.name || data.name,
            leads: data.leads.sort((a,b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()),
        };
    });

    return allCustomers.sort((a,b) => {
        const aDate = a.leads[0]?.createdAt || a.profileCreatedAt || 0;
        const bDate = b.leads[0]?.createdAt || b.profileCreatedAt || 0;
        return new Date(bDate).getTime() - new Date(aDate).getTime();
    });
  }, [leads, customersData]);

  const cskhLeads = useMemo(() => {
    return leads
        .filter(lead => lead.status === 'completed')
        .sort((a,b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
  }, [leads]);


  // --- HANDLERS ---

  const handleOpenAddModal = (statusId?: string) => {
    setNewLeadStatus(statusId || statuses[0]?.id || 'new');
    setIsAddModalOpen(true);
  };

  // Update Customer Logic
  const handleUpdateCustomerData = async (phone: string, data: Partial<CustomerData>) => {
    // Optimistic Update
    setCustomersData(prev => ({
        ...prev,
        [phone]: { ...prev[phone] || { phone, generalNotes: '', tags: [] }, ...data }
    }));

    if (selectedCustomer && selectedCustomer.phone === phone) {
        setSelectedCustomer(prev => prev ? {...prev, ...data} : null);
    }

    // DB Update
    try {
        const { error } = await supabase
            .from('customers')
            .update({
                name: data.name,
                email: data.email,
                address: data.address,
                location: data.location,
                general_notes: data.generalNotes,
                tags: data.tags,
                tax_code: data.taxCode,
                business_industry: data.businessIndustry,
                customer_group: data.customerGroup,
                website: data.website,
                relationship_status: data.relationshipStatus,
                profile_completeness: data.profileCompleteness
            })
            .eq('phone', phone);

        if (error) throw error;
    } catch (err) {
        console.error("Failed to update customer:", err);
        alert("Lỗi khi lưu thông tin khách hàng.");
        fetchData(); // Revert
    }
  };

  const handleOpenAddCustomerModal = () => {
    setEditingCustomer(null);
    setIsCustomerModalOpen(true);
  };

  const handleOpenEditCustomerModal = (customer: Customer) => {
    setEditingCustomer(customer);
    setIsCustomerModalOpen(true);
  };

  const handleSaveCustomer = async (data: CustomerData) => {
    const isEdit = !!editingCustomer;

    try {
        if (isEdit) {
            await handleUpdateCustomerData(editingCustomer!.phone, data);
        } else {
             // Check exist
             if (customersData[data.phone]) {
                alert('Lỗi: Số điện thoại này đã tồn tại trong hệ thống.');
                return;
            }

            const newCustomer = {
                phone: data.phone,
                name: data.name,
                email: data.email,
                address: data.address,
                location: data.location,
                general_notes: data.generalNotes,
                tags: data.tags,
                website: data.website,
                creator: sales.find(s => s.id === currentUser)?.name || 'Không rõ',
                created_at: new Date().toISOString()
            };

            const { error } = await supabase.from('customers').insert([newCustomer]);
            if (error) throw error;

            // Update State
            setCustomersData(prev => ({
                ...prev,
                [data.phone]: { ...data, profileCreatedAt: newCustomer.created_at, creator: newCustomer.creator }
            }));
        }
        setIsCustomerModalOpen(false);
        setEditingCustomer(null);
    } catch (err) {
        console.error("Error saving customer", err);
        alert("Có lỗi xảy ra khi lưu khách hàng.");
    }
  };

  const handleDeleteCustomer = async (phone: string) => {
    if (window.confirm('Bạn có chắc chắn muốn xóa khách hàng này? Mọi cơ hội bán hàng liên quan cũng sẽ bị xóa vĩnh viễn.')) {
        try {
            const { error } = await supabase.from('customers').delete().eq('phone', phone);
            if (error) throw error;

            // Update State
            setLeads(prev => prev.filter(l => l.phone !== phone));
            setCustomersData(prev => {
                const newState = { ...prev };
                delete newState[phone];
                return newState;
            });
            handleCloseCustomerDetail();
        } catch (err) {
            console.error("Error deleting customer", err);
            alert("Không thể xóa khách hàng.");
        }
    }
  };

  const handleAddNoteToLead = async (leadId: string, content: string) => {
     const newNote = {
        id: `note_${Date.now()}`,
        lead_id: leadId,
        content: content.trim(),
        created_by: currentUser,
        created_at: new Date().toISOString()
     };

     // Optimistic Update
     const mappedNote: Note = {
        id: newNote.id,
        content: newNote.content,
        createdBy: newNote.created_by,
        createdAt: newNote.created_at
     };

    setLeads(prevLeads => prevLeads.map(lead => 
      lead.id === leadId 
        ? { ...lead, notes: [mappedNote, ...lead.notes], updatedAt: new Date().toISOString() } 
        : lead
    ));

    // DB Insert
    try {
        const { error } = await supabase.from('notes').insert([newNote]);
        if (error) throw error;
        // Also update lead updated_at
        await supabase.from('leads').update({ updated_at: new Date().toISOString() }).eq('id', leadId);
    } catch (err) {
        console.error("Error adding note", err);
        // revert logic ideally
    }
  };

  const processLeadStatusUpdate = (leadToUpdate: Lead): Lead => {
    const updatedLead = { ...leadToUpdate };
    const isContacting = updatedLead.status === 'contacting';
    const isScheduled = ['scheduled', 'completed'].includes(updatedLead.status);

    if (isContacting) updatedLead.appointmentDate = null;
    else updatedLead.projectedAppointmentDate = null;

    if (!isScheduled) updatedLead.appointmentDate = null;

    if (updatedLead.status === 'completed' && !updatedLead.cskhStatus) {
        updatedLead.cskhStatus = cskhStatuses[0]?.id || 'cskh_1_completed';
    }

    return { ...updatedLead, updatedAt: new Date().toISOString() };
  }


  const handleUpdateLead = async (updatedLead: Lead) => {
    const processedLead = processLeadStatusUpdate(updatedLead);

    // Optimistic
    setLeads(prevLeads => prevLeads.map(lead => lead.id === processedLead.id ? processedLead : lead));
    setSelectedLead(null);

    // DB Update
    try {
        const { error } = await supabase.from('leads').update({
            status: processedLead.status,
            assigned_to: processedLead.assignedTo,
            service: processedLead.service,
            description: processedLead.description,
            priority: processedLead.priority,
            potential_revenue: processedLead.potentialRevenue,
            appointment_date: processedLead.appointmentDate,
            projected_appointment_date: processedLead.projectedAppointmentDate,
            cskh_status: processedLead.cskhStatus,
            updated_at: processedLead.updatedAt
        }).eq('id', processedLead.id);

        if (error) throw error;
    } catch (err) {
        console.error("Error updating lead", err);
        alert("Lỗi cập nhật cơ hội.");
        fetchData();
    }
  };

  const handleAddLead = async (newLeadData: Omit<Lead, 'id' | 'createdAt' | 'updatedAt' | 'notes'>) => {
    const tempId = `lead_${Date.now()}`;
    const now = new Date().toISOString();

    const newLead: Lead = {
      ...newLeadData,
      id: tempId,
      notes: [],
      createdAt: now,
      updatedAt: now,
    };

    // Optimistic Update
    setLeads(prevLeads => [newLead, ...prevLeads]);
    setIsAddModalOpen(false);

    // DB Logic
    try {
        // 1. Ensure Customer Exists
        if (!customersData[newLead.phone]) {
            const { error: custError } = await supabase.from('customers').upsert({
                phone: newLead.phone,
                name: newLead.name,
                source: newLead.source, // Initial source
                creator: sales.find(s => s.id === (newLead.assignedTo || currentUser))?.name || 'Không rõ',
            }, { onConflict: 'phone' });

            if (custError) throw custError;

            // Update local customer data map
             setCustomersData(prev => ({
                ...prev,
                [newLead.phone]: {
                    phone: newLead.phone,
                    name: newLead.name,
                    source: newLead.source,
                    creator: sales.find(s => s.id === (newLead.assignedTo || currentUser))?.name || 'Không rõ',
                    generalNotes: '',
                    tags: []
                }
             }));
        }

        // 2. Insert Lead
        const { error: leadError } = await supabase.from('leads').insert([{
            id: tempId,
            phone: newLead.phone,
            source: newLead.source,
            assigned_to: newLead.assignedTo,
            status: newLead.status,
            service: newLead.service,
            description: newLead.description,
            potential_revenue: newLead.potentialRevenue,
            projected_appointment_date: newLead.projectedAppointmentDate,
            created_at: now,
            updated_at: now
        }]);

        if (leadError) throw leadError;

    } catch (err) {
        console.error("Error adding lead", err);
        alert("Lỗi khi thêm mới. Vui lòng thử lại.");
        setLeads(prev => prev.filter(l => l.id !== tempId)); // Revert
    }
  };

  const handleLeadStatusChangeOnDrop = async (leadId: string, newStatusId: string) => {
     // Optimistic
    let leadToUpdate: Lead | undefined;
    setLeads(prevLeads => {
      const lead = prevLeads.find(l => l.id === leadId);
      if (!lead) return prevLeads;
      leadToUpdate = lead;

      const updatedLeadData = { ...lead, status: newStatusId };

      // If needs details, don't update DB yet, just open modal (handled by UI logic below return)
      if ((newStatusId === 'scheduled' && !lead.appointmentDate) || (newStatusId === 'contacting' && !lead.projectedAppointmentDate)) {
        return prevLeads; 
      }

      const processedLead = processLeadStatusUpdate(updatedLeadData);
      return prevLeads.map(l => l.id === leadId ? processedLead : l);
    });

    if (!leadToUpdate) return;

    // Check if we need to open modal
    if ((newStatusId === 'scheduled' && !leadToUpdate.appointmentDate) || (newStatusId === 'contacting' && !leadToUpdate.projectedAppointmentDate)) {
         setSelectedLead({ ...leadToUpdate, status: newStatusId });
         return;
    }

    // DB Update for direct drops
    const processed = processLeadStatusUpdate({ ...leadToUpdate, status: newStatusId });
    try {
        await supabase.from('leads').update({
            status: processed.status,
            appointment_date: processed.appointmentDate,
            projected_appointment_date: processed.projectedAppointmentDate,
            updated_at: processed.updatedAt,
            cskh_status: processed.cskhStatus
        }).eq('id', leadId);
    } catch(err) {
        console.error(err);
        fetchData();
    }
  };

  const handleAcceptLead = async (leadId: string) => {
    if (!currentUser) {
        alert("Vui lòng chọn bạn là sale nào để nhận lead.");
        return;
    }

    const leadToUpdate = leads.find(l => l.id === leadId);
    if (!leadToUpdate) return;

    const processedLead = processLeadStatusUpdate({
        ...leadToUpdate,
        status: 'contacting',
        assignedTo: currentUser
    });

    setLeads(prevLeads => prevLeads.map(lead => lead.id === leadId ? processedLead : lead));

    try {
        await supabase.from('leads').update({
            status: 'contacting',
            assigned_to: currentUser,
            updated_at: processedLead.updatedAt
        }).eq('id', leadId);
    } catch (err) { console.error(err); }
  };

  const handleUpdateLeadCskhStatus = async (leadId: string, newCskhStatusId: string) => {
    const now = new Date().toISOString();
    setLeads(prevLeads =>
      prevLeads.map(lead =>
        lead.id === leadId
          ? { ...lead, cskhStatus: newCskhStatusId, updatedAt: now }
          : lead
      )
    );
     try {
        await supabase.from('leads').update({
            cskh_status: newCskhStatusId,
            updated_at: now
        }).eq('id', leadId);
    } catch (err) { console.error(err); }
  };

  const handleSelectCustomer = (customer: Customer) => {
    setSelectedCustomer(customer);
    setCustomerViewMode('detail');
  };

  const handleCloseCustomerDetail = () => {
    setCustomerViewMode('list');
    setSelectedCustomer(null);
  };

  if (isLoading) {
      return <div className="h-screen w-full flex items-center justify-center bg-slate-50 text-slate-500">Đang tải dữ liệu...</div>;
  }

  return (
    <div className="flex h-screen bg-slate-50 font-sans antialiased">
      <Sidebar 
        activeView={activeView} 
        setActiveView={setActiveView} 
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
        onAddLead={() => handleOpenAddModal()}
      />
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black bg-opacity-50 z-30 md:hidden"
          onClick={() => setIsSidebarOpen(false)}
        ></div>
      )}
      <div className="flex-1 flex flex-col overflow-hidden">
        <MainHeader 
          onAddLead={() => handleOpenAddModal()} 
          onToggleSidebar={() => setIsSidebarOpen(true)}
          sales={sales}
          currentUser={currentUser}
          onSetCurrentUser={setCurrentUser}
        />

        <main className="flex-1 overflow-x-auto overflow-y-auto bg-white">
           {activeView === 'sales' && (
            <KanbanBoard 
              leads={sortedLeads}
              sales={sales}
              statuses={statuses}
              onSelectLead={setSelectedLead}
              onUpdateLeadStatus={handleLeadStatusChangeOnDrop}
              onAddLead={handleOpenAddModal}
              onAcceptLead={handleAcceptLead}
              sources={uniqueSources}
              selectedSource={sourceFilter}
              onSourceChange={setSourceFilter}
              onCustomizeStatuses={() => setIsStatusModalOpen(true)}
              selectedSale={saleFilter}
              onSaleChange={setSaleFilter}
            />
          )}

          {activeView === 'cskh' && (
              <CskhView
                leads={cskhLeads}
                statuses={cskhStatuses}
                onSelectLead={setSelectedLead}
                onUpdateLeadCskhStatus={handleUpdateLeadCskhStatus}
                onCustomizeStatuses={() => setIsCskhStatusModalOpen(true)}
              />
          )}

          {activeView === 'revenue' && (
            <div className="p-2 sm:p-4">
              <CalendarView leads={leads} onSelectLead={setSelectedLead} />
            </div>
          )}

          {activeView === 'customers' && (
            customerViewMode === 'list' 
               ? <CustomerList customers={customers} onSelectCustomer={handleSelectCustomer} onAddCustomer={handleOpenAddCustomerModal}/>
               : selectedCustomer && <CustomerDetailView
                    customer={selectedCustomer}
                    onClose={handleCloseCustomerDetail}
                    onSelectLead={setSelectedLead}
                    onUpdateCustomer={handleUpdateCustomerData}
                    sales={sales}
                    statuses={statuses}
                    onEdit={handleOpenEditCustomerModal}
                    onDelete={handleDeleteCustomer}
                    onAddNote={handleAddNoteToLead}
                    currentUser={currentUser}
                 />
          )}

          {activeView !== 'sales' && activeView !== 'revenue' && activeView !== 'customers' && activeView !== 'cskh' && (
             <div className="p-8 text-center text-slate-500">
                <h2 className="text-xl font-semibold">Tính năng đang được phát triển</h2>
                <p>Vui lòng quay lại sau.</p>
             </div>
          )}

        </main>
      </div>

      {selectedLead && (
        <LeadDetailModal
          lead={selectedLead}
          sales={sales}
          statuses={statuses}
          cskhStatuses={cskhStatuses}
          context={selectedLead.cskhStatus || selectedLead.status === 'completed' ? 'cskh' : 'sales'}
          onClose={() => setSelectedLead(null)}
          onSave={handleUpdateLead}
          currentUser={currentUser}
        />
      )}

      {isAddModalOpen && (
        <AddLeadModal
          sales={sales}
          customers={customers}
          onClose={() => setIsAddModalOpen(false)}
          onSave={handleAddLead}
          defaultStatus={newLeadStatus}
        />
      )}

      {isCustomerModalOpen && (
        <CustomerFormModal
            customerToEdit={editingCustomer}
            onClose={() => { setIsCustomerModalOpen(false); setEditingCustomer(null); }}
            onSave={handleSaveCustomer}
        />
      )}

      {isStatusModalOpen && (
        <StatusManagementModal
            statuses={statuses}
            leads={leads}
            onSave={(newStatuses) => {
                setStatuses(newStatuses);
                setIsStatusModalOpen(false);
            }}
            onClose={() => setIsStatusModalOpen(false)}
            statusKey="status"
        />
      )}

      {isCskhStatusModalOpen && (
        <StatusManagementModal
            statuses={cskhStatuses}
            leads={cskhLeads}
            onSave={(newStatuses) => {
                setCskhStatuses(newStatuses);
                setIsCskhStatusModalOpen(false);
            }}
            onClose={() => setIsCskhStatusModalOpen(false)}
            statusKey="cskhStatus"
            defaultStatusId={cskhStatuses[0]?.id}
        />
      )}
    </div>
  );
}

export default App;
